insert into result_table_config (
    id, table_code, table_name, table_comment, owner_department_id, storage_datasource,
    auto_create_table, auto_add_column, ddl_status, status, created_by, created_at, updated_at
) values (
    #{id}, #{tableCode}, #{tableName}, #{tableComment}, #{ownerDepartmentId}, #{storageDatasource},
    #{autoCreateTable}, #{autoAddColumn}, #{ddlStatus}, #{status}, #{createdBy}, #{createdAt}, #{updatedAt}
)

insert into result_table_column_config (
    id, result_table_id, column_name, column_name_cn, db_type, type_params, field_length,
    field_precision, field_scale, required, default_value, validation_rule, sort_no, enabled,
    created_at, updated_at
) values (
    #{id}, #{resultTableId}, #{columnName}, #{columnNameCn}, #{dbType}, #{typeParams}, #{fieldLength},
    #{fieldPrecision}, #{fieldScale}, #{required}, #{defaultValue}, #{validationRule}, #{sortNo}, #{enabled},
    #{createdAt}, #{updatedAt}
)
